@Override
public void close() throws IOException {
    if (open.compareAndSet(true, false)) {
        try {
            finalizeSegment(FinalizeWhen.ALWAYS, SealReason.DLQ_CLOSE);
        } finally {
            try {
                releaseFileLock();
            } finally {
                flusherService.shutdown();
                closeConsumedSegmentsNotification();
            }
        }
    }
}

